from app.ai.conversation_memory import landlord_messages
import pytest

def test_none_input_returns_empty_list():
    assert landlord_messages(None) == []

def test_empty_list_input_returns_empty_list():
    assert landlord_messages([]) == []

def test_exact_matching_and_order_preserved():
    messages = [
        {"sender": "landlord", "message": "Can you share your WhatsApp number?"},
        {"sender": "tenant", "message": "Sure, here it is."},
        {"direction": "inbound", "message": "Please confirm the viewing time."},
        {"sender": "Landlord", "message": "Is the deposit ready?"}
    ]
    expected = [
        {"sender": "landlord", "message": "Can you share your WhatsApp number?"},
        {"direction": "inbound", "message": "Please confirm the viewing time."},
        {"sender": "Landlord", "message": "Is the deposit ready?"}
    ]
    assert landlord_messages(messages) == expected

def test_sender_fallback_to_direction_and_empty_string_behavior():
    messages = [
        {"sender": "", "direction": "inbound", "message": "Fallback to direction"},
        {"sender": None, "direction": "landlord", "message": "Fallback with None sender"},
        {"sender": "", "direction": "", "message": "No sender or direction"},
        {"message": "Missing both keys"}
    ]
    expected = [
        {"sender": "", "direction": "inbound", "message": "Fallback to direction"},
        {"sender": None, "direction": "landlord", "message": "Fallback with None sender"},
    ]
    assert landlord_messages(messages) == expected

def test_case_insensitivity_and_exact_matching():
    messages = [
        {"sender": "LANDLORD", "message": "Uppercase landlord"},
        {"sender": "InBound", "message": "Mixed case inbound"},
        {"sender": "landlords", "message": "Substring landlord"},
        {"direction": "INBOUND", "message": "Uppercase direction inbound"},
        {"direction": "outbound", "message": "Non-matching direction"},
    ]
    expected = [
        {"sender": "LANDLORD", "message": "Uppercase landlord"},
        {"sender": "InBound", "message": "Mixed case inbound"},
        {"direction": "INBOUND", "message": "Uppercase direction inbound"},
    ]
    assert landlord_messages(messages) == expected

def test_no_matching_senders_returns_empty_list():
    messages = [
        {"sender": "tenant", "message": "Tenant message"},
        {"direction": "outbound", "message": "Outbound message"},
        {"sender": "", "direction": "", "message": "Empty sender and direction"},
    ]
    assert landlord_messages(messages) == []

def test_returned_messages_are_original_objects():
    msg1 = {"sender": "landlord", "message": "Message 1"}
    msg2 = {"direction": "inbound", "message": "Message 2"}
    messages = [msg1, msg2]
    result = landlord_messages(messages)
    assert result == messages
    assert result[0] is msg1
    assert result[1] is msg2
